import{_ as i,c as t,o as e,ah as n}from"./chunks/framework.C-x9UAyH.js";const c="/ec2/aws_1_pagina_inicio_consola_aws.png",s="/ec2/aws_2_panel_principal_ec2.png",l="/ec2/aws_3_lanzar_instancia.png",r="/ec2/aws_4_tipo_instancia_par_de_claves_config_red.png",o="/ec2/aws_5_configuraciones_de_red.png",d="/ec2/aws_6_lanzamiento_de_instancia_correcto.png",_="/ec2/aws_10_grupo_de_seguridad.png",p="/ec2/aws_13_conectar_maquina_ec2.png",g="/ec2/aws_14_ingresando_a_consola.png",m="/ec2/aws_15_instalacion_git_parte_1.png",u="/ec2/aws_16_instalacion_git_parte_2.png",h="/ec2/aws_17_instancia_detenida.png",b="/ec2/aws_18_ip_elastica.png",w="/ec2/aws_19_asignar_ip_elastica.png",q="/ec2/aws_20_asociar_ip_elastica.png",P="/ec2/aws_21_seleccionar_ip_elastica_para_asociar.png",I="/ec2/aws_22_direccion_ip_elastica_asociada.png",C="/ec2/aws_23_ip_elastica_en_ejecucion.png",E="/ec2/aws_24_conexion_de_ip_publica.png",f="/ec2/aws_25_consola_ip_publica.png",T=JSON.parse('{"title":"Instancia EC2","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"aws/lanzamiento_instancia_ec2.md","filePath":"aws/lanzamiento_instancia_ec2.md","lastUpdated":1760459112000}'),S={name:"aws/lanzamiento_instancia_ec2.md"};function z(A,a,v,x,k,y){return e(),t("div",null,[...a[0]||(a[0]=[n('<h1 id="instancia-ec2" tabindex="-1">Instancia EC2 <a class="header-anchor" href="#instancia-ec2" aria-label="Permalink to &quot;Instancia EC2&quot;">​</a></h1><h2 id="lanzamiento-de-instancia-ec2" tabindex="-1">Lanzamiento de instancia EC2 <a class="header-anchor" href="#lanzamiento-de-instancia-ec2" aria-label="Permalink to &quot;Lanzamiento de instancia EC2&quot;">​</a></h2><p align="center"><img src="'+c+'" width="800" alt="ec2 1 - página inicio"></p><ol><li>Página de inicio de la consola de AWS</li></ol><br><p align="center"><img src="'+s+'" width="800" alt="ec2 2 - panel principal"></p><ol start="2"><li>Menú principal de EC2. Seleccionar &quot;Lanzar la instancia&quot;</li></ol><br><p align="center"><img src="'+l+'" width="800" alt="ec2 3 - lanzar instancia"></p><ol start="3"><li>Dar nombre a la instancia, seleccionar la imagen del sistema operativo</li></ol><br><p align="center"><img src="'+r+'" width="800" alt="ec2 4 - nombre y SO"></p><ol start="4"><li>Seleccionar el tipo de instancia, par de claves y Configuración de red</li></ol><br><p align="center"><img src="'+o+'" width="800" alt="ec2 5 - configuraciones de red"></p><ol start="5"><li>Configuración de red previa a lanzar la instancia. Se debe seleccionar la subred <strong>us-east-1a</strong></li></ol><br><p align="center"><img src="'+d+'" width="800" alt="ec2 6 - lanzamiento correcto"></p><ol start="6"><li>Lanzamiento de la instancia correcto</li></ol><br><p align="center"><img src="'+_+'" width="800" alt="ec2 7 - grupo de seguridad"></p><ol start="7"><li>Detalle de la instancia: Sección &quot;Seguridad&quot;. Al hacer click en el grupo de seguridad, se pueden editar las reglas de entrada.</li></ol><h2 id="conectar-la-instancia-ec2" tabindex="-1">Conectar la instancia EC2 <a class="header-anchor" href="#conectar-la-instancia-ec2" aria-label="Permalink to &quot;Conectar la instancia EC2&quot;">​</a></h2><p>Estando en la pantalla &quot;Instancias&quot;, se debe hacer click al botón <strong>CONECTAR</strong> para conectarse a la instancia EC2.</p><p align="center"><img src="'+p+'" width="800" alt="ec2 8 - conectar máquina ec2"></p><ol start="8"><li>Conectando a la instancia EC2</li></ol><p align="center"><img src="'+g+'" width="800" alt="ec2 9 - ingresando a consola"></p><ol start="9"><li>Ingresando a la consola</li></ol><h2 id="instalacion-de-git" tabindex="-1">Instalación de Git <a class="header-anchor" href="#instalacion-de-git" aria-label="Permalink to &quot;Instalación de Git&quot;">​</a></h2><p align="center"><img src="'+m+'" width="800" alt="ec2 10 - instalación de git 1"></p><ol start="10"><li>Instalación de git. Con los comandos <strong>sudo yum list git</strong> y <strong>sudo yum install git</strong></li></ol><br><p align="center"><img src="'+u+'" width="800" alt="ec2 11 - instalación de git 2"></p><br><p align="center"><img src="'+h+'" width="800" alt="ec2 12 - instancia detenida"></p><ol start="11"><li>Instancia detenida. En el botón <strong>Estado de la instancia</strong>, seleccionar &quot;Detener&quot;. La IP pública se borra, por lo que al momento de subir nuevamente la instancia, la ip pública será otra.</li></ol><h2 id="ip-elastica" tabindex="-1">IP elástica <a class="header-anchor" href="#ip-elastica" aria-label="Permalink to &quot;IP elástica&quot;">​</a></h2><p>Una IP elástica es una dirección IP pública estática que se puede asociar a las instancias EC2.</p><table tabindex="0"><thead><tr><th>Característica</th><th>IP Pública Normal</th><th>IP Elástica</th></tr></thead><tbody><tr><td>Asignación</td><td>Automática al iniciar EC2</td><td>Manual, por el usuario</td></tr><tr><td>Persisntencia</td><td>Se pierde al detener EC2</td><td>Se mantiene incluso al detener EC2</td></tr><tr><td>Transferibilidad</td><td>No se puede transferir</td><td>Se puede mover entre instancias</td></tr><tr><td>Costo</td><td>Gratis</td><td>Gratis sólo si está en uso</td></tr></tbody></table><br><p align="center"><img src="'+b+'" width="800" alt="ec2 13 - ip elástica"></p><ol start="12"><li>Creando una IP elástica. En el sidebar &quot;Red y Seguridad&quot;, ingresar a &quot;Direcciones IP elásticas&quot; y hacer click al botón <strong>Asignar dirección IP elástica</strong>.</li></ol><br><p align="center"><img src="'+w+'" width="800" alt="ec2 14 - asignar ip elástica"></p><ol start="13"><li>Asignar una dirección IP elástica. Sólo presionar el botón &quot;Asignar&quot;.</li></ol><br><p align="center"><img src="'+q+'" width="800" alt="ec2 15 - asociar ip elástica"></p><ol start="14"><li>Asociar la IP elástica.</li></ol><br><p align="center"><img src="'+P+'" width="800" alt="ec2 15 - seleccionar ip elástica"></p><ol start="15"><li>Seleccionar IP elástica para asociar. En el botón &quot;Acciones&quot;, seleccionar la opción &quot;Dirección IP elástica asociada&quot;.</li></ol><br><p align="center"><img src="'+I+'" width="800" alt="ec2 16 - dirección ip elástica asociada"></p><ol start="16"><li>Dirección IP elástica asociada.</li></ol><br><p align="center"><img src="'+C+'" width="800" alt="ec2 17 - ip elástica en ejecución"></p><ol start="17"><li>IP elástica en ejecución. Al volver a las instancias, si ésta se detiene, se puede ver que la dirección IPv4 pública se mantiene al refrescar la página.</li></ol><br><p align="center"><img src="'+E+'" width="800" alt="ec2 17 - conexión de ip"></p><ol start="18"><li>Demostración de la conexión de IP elástica.</li></ol><br><p align="center"><img src="'+f+'" width="800" alt="ec2 18 - consola con IP elástica"></p><ol start="19"><li>Consola con la IP elástica.</li></ol>',63)])])}const N=i(S,[["render",z]]);export{T as __pageData,N as default};
